const d = $input.item.json.body || $input.item.json;
const data = d.data || d;
const tier = data.reminderTier || 1;
const days = data.daysPending || 3;
const name = data.clientName || 'Estimado proveedor';

const urgent = tier >= 3;
const headerColor = urgent ? '#991b1b' : tier >= 2 ? '#b91c1c' : '#ea580c';
const alertBg = urgent ? '#fee2e2' : '#fff3cd';
const alertBorder = urgent ? '#fecaca' : '#ffeaa7';
const alertText = urgent ? '#991b1b' : '#856404';

const html = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">
  <div style="background:${headerColor};padding:24px;text-align:center;border-radius:8px 8px 0 0">
    <h1 style="color:#fff;margin:0;font-size:22px">⏰ ${data.reminderLabel || 'Recordatorio'}</h1>
    <p style="color:rgba(255,255,255,.8);margin:6px 0 0;font-size:14px">Complemento de Pago Pendiente</p>
  </div>
  <div style="padding:30px;background:#f8f9fa">
    <p style="color:#333;font-size:18px">Hola <strong>${name}</strong>,</p>
    <p style="color:#555;line-height:1.6">Te recordamos que necesitamos el <strong>complemento de pago (REP)</strong> para cerrar el proceso contable.</p>
    <div style="background:${alertBg};border:1px solid ${alertBorder};padding:20px;border-radius:8px;margin:24px 0">
      <p style="color:${alertText};margin:0 0 10px;font-weight:bold">📋 Acción Requerida</p>
      <p style="color:${alertText};margin:0 0 10px">Han pasado <strong>${days} días</strong> desde que se realizó el pago. Envía el complemento para cerrar el proceso.</p>
      <p style="color:${alertText};margin:0;font-weight:bold">Puedes enviarlo respondiendo a este correo.</p>
    </div>
    <p style="color:#888;font-size:13px;text-align:center;margin-top:30px">Lolita — Equipo de Tesorería · Grupo Orsega</p>
  </div>
</div>`;

return {
  json: {
    to: d.to || data.clientEmail,
    subject: d.subject || `${data.reminderLabel} — Complemento de Pago Pendiente`,
    html: html
  }
};
